func (a *entitlementDBAdapter) GetEntitlement(ctx context.Context, id models.NamespacedID) (*entitlement.Entitlement, error) {
	return entutils.TransactingRepo(ctx, a, func(ctx context.Context, repo *entitlementDBAdapter) (*entitlement.Entitlement, error) {
		res, err := withAllUsageResets(repo.db.Entitlement.Query(), []string{id.Namespace}).
			Where(db_entitlement.ID(id.ID), db_entitlement.Namespace(id.Namespace),
				db_entitlement.Or(db_entitlement.DeletedAtGT(clock.Now()), db_entitlement.DeletedAtIsNil())).First(ctx)
		if err != nil {
			if db.IsNotFound(err) { return nil, &entitlement.NotFoundError{EntitlementID: id} }
			return nil, err
		}
		return repo.mapEntitlementEntity(res)
	})
}

func (c *connector) GetValue(ctx context.Context, e *entitlement.Entitlement, at time.Time) (entitlement.EntitlementValue, error) {
	if _, err := ParseFromGenericEntitlement(e); err != nil { return nil, err }
	return &BooleanEntitlementValue{}, nil
}

func (e *connector) GetEntitlementBalance(ctx context.Context, id models.NamespacedID, at time.Time) (*EntitlementBalance, error) {
	ctx, span := e.tracer.Start(ctx, "meteredentitlement.GetEntitlementBalance")
	defer span.End()
	nsOwner := models.NamespacedID{Namespace: id.Namespace, ID: id.ID}
	startOfPeriod, err := e.ownerConnector.GetUsagePeriodStartAt(ctx, nsOwner, at)
	if err != nil { return nil, err }
	res, err := e.balanceConnector.GetBalanceAt(ctx, nsOwner, at)
	if err != nil { return nil, err }
	return &EntitlementBalance{EntitlementID: id.ID, Balance: res.Snapshot.Balance(), Overage: res.Snapshot.Overage, StartOfPeriod: startOfPeriod}, nil
}

func (c *service) ScheduleEntitlement(ctx context.Context, input entitlement.CreateEntitlementInputs) (*entitlement.Entitlement, error) {
	return transaction.Run(ctx, c.entitlementRepo, func(ctx context.Context) (*entitlement.Entitlement, error) {
		if err := input.Validate(); err != nil { return nil, models.NewGenericValidationError(err) }
		feat, err := c.featureConnector.GetFeature(ctx, input.Namespace, *input.FeatureKey, feature.IncludeArchivedFeatureFalse)
		if err != nil { return nil, &feature.FeatureNotFoundError{ID: *input.FeatureKey} }
		if err := c.lockUniqueScope(ctx, input.UsageAttribution.ID, feat.Key); err != nil { return nil, err }
		connector, err := c.getTypeConnector(input)
		if err != nil { return nil, err }
		repoInputs, err := connector.BeforeCreate(input, *feat)
		if err != nil { return nil, err }
		ent, err := c.entitlementRepo.CreateEntitlement(ctx, *repoInputs)
		if err != nil { return nil, err }
		if err := connector.AfterCreate(ctx, ent); err != nil { return nil, err }
		return ent, c.publisher.Publish(ctx, entitlement.NewEntitlementCreatedEventPayloadV2(*ent, cust))
	})
}

func (e SnapshotEvent) Validate() error {
	var errs []error
	if err := e.Operation.Validate(); err != nil { errs = append(errs, err) }
	if e.Entitlement.ID == "" { errs = append(errs, errors.New("entitlementId is required")) }
	if err := e.Namespace.Validate(); err != nil { errs = append(errs, err) }
	switch e.Operation {
	case ValueOperationUpdate, ValueOperationReset:
		if e.Value == nil { errs = append(errs, errors.New("balance is required for balance update/reset")) }
	}
	return errors.Join(errs...)
}
